   117|      orderBy('createdAt', 'desc')
   118|    );
   119|    const snap = await getDocs(q);
   120|    const items = snap.docs.map(d => parseEquipment(d.id, d.data() as Record<string, unknown>));
   121|    console.log('[Firestore] Fetched', items.length, 'equipment items (indexed)');
