   314|export async function updateRequestStatus(
   315|  requestId: string,
   316|  status: EquipmentRequest['status'],
   317|  currentUid: string
   318|): Promise<void> {
   319|  const db = getFirebaseDb();
   320|  console.log('[Firestore] Updating request status:', requestId, '->', status);
   321|
   322|  const snap = await getDoc(doc(db, 'equipmentRequests', requestId));
   323|  if (!snap.exists()) throw new Error('Request not found');
   324|
   325|  const request = snap.data();
   326|  const isProvider = request.providerUid === currentUid;
   327|  const isCustomer = request.customerUid === currentUid;
   328|
   329|  const validTransitions: Record<string, { allowed: string[]; who: 'provider' | 'customer' | 'both' }> = {
   330|    pending: { allowed: ['accepted', 'rejected', 'cancelled'], who: 'both' },
   331|    accepted: { allowed: ['in_progress', 'cancelled'], who: 'both' },
   332|    in_progress: { allowed: ['completed'], who: 'provider' },
   333|  };
   334|
   335|  const current = request.status as string;
   336|  const rule = validTransitions[current];
   337|
   338|  if (!rule || !rule.allowed.includes(status)) {
   339|    throw new Error(`Invalid status transition: ${current} -> ${status}`);
   340|  }
   341|
   342|  if (rule.who === 'provider' && !isProvider) {
   343|    throw new Error('Only the provider can perform this action');
   344|  }
   345|
   346|  if (status === 'cancelled' && !isCustomer && !isProvider) {
   347|    throw new Error('Only participants can cancel');
   348|  }
   349|
   350|  const updates: Record<string, unknown> = {
   351|    status,
   352|    updatedAt: serverTimestamp(),
   353|  };
   354|
   355|  if (status === 'accepted') {
   356|    updates.allowChat = true;
   357|  }
   358|
   359|  if (status === 'completed' || status === 'rejected' || status === 'cancelled') {
   360|    updates.allowChat = false;
   361|  }
   362|
   363|  await updateDoc(doc(db, 'equipmentRequests', requestId), updates);
